				CRX__C__CHAR__GET_NEXT_CODE_POINT_FROM_UTF8_CHAR_ARRAY(tChars, tCodePoint, 
						tNumberOfRemainingCharacters, _fgdgdf, CRXM__FALSE, CRXM__FALSE);

