				Crx_C_String tRaw_currentFullPathFromOs /*= ?*/; //IN OS ENCODING, NOT UTF8. FROM OS.
				Crx_C_String tRaw_entityNameFromOs__atFound /*= ?*/; //IN OS ENCODING, NOT UTF8. 
																		  //FROM OS.

