			//		THE PATH WAS NOT IN UTF8.
			tEndIndex = crx_c_string_getIndexOfFirstReverseOccuranceOf2(
					&vVerifiedRoute, crx_c_string_getSize(&vVerifiedRoute) - (vIsADirectory ? 2 : 1), 
					CRX__C__OS__FILE_SYSTEM__SEPERATOR_STRING, 0);
					
