		Crx_C_Os_FileSystem_Existance tExistance = CRX__C__OS__FILE_SYSTEM__EXISTANCE__NULL;

		if(crx_c_os_fileSystem_internal_verifyFileSystemPath2(pContract, 
				CRX__C__OS__FILE_SYSTEM__OPERATION__READ, NULL, 
				pDepthLimitOfReparsePointsOfFullPath, 
				&tExistance, &vVerifiedPathPrefix, &vVerifiedRoute, NULL))
		{
			if(tExistance == CRX__C__OS__FILE_SYSTEM__EXISTANCE__EXISTS)
				{vIsNoError = crx_c_string_appendCString(&vFullPath, &vVerifiedPathPrefix, pError);}
			else
			{
				assert(tExistance == CRX__C__OS__FILE_SYSTEM__EXISTANCE__DOES_NOT_EXIST);

				vIsNoError = false;
			}
		}
		else
			{vIsNoError = false;}

		if(vIsNoError && crx_c_string_isEqualTo2(&vVerifiedRoute, 
				CRX__C__OS__FILE_SYSTEM__SEPERATOR_STRING))
			{vIsNoError = false;}

		if(vIsNoError)
		{
			size_t tEndIndex = 0;

			vIsADirectory = crx_c_string_isEndingWith2(&vVerifiedRoute, 
					CRX__C__OS__FILE_SYSTEM__SEPERATOR_STRING);

			//REMEMBER: THE FOLLOWING WOULD BE UNSAFE IF THIS WAS NOT THE SEPERATOR CHARACTER AND
			//		THE PATH WAS NOT IN UTF8.
			tEndIndex = crx_c_string_getIndexOfFirstReverseOccuranceOf2(
					&vVerifiedRoute, crx_c_string_getSize(&vVerifiedRoute) - (vIsADirectory ? 2 : 1), 
					CRX__C__OS__FILE_SYSTEM__SEPERATOR_STRING, 0);

			if(tStartIndex != ((size_t)(-1)))
			{
				if(vIsNoError && !crx_c_string_appendChars(&vFullPath,
						crx_c_string_getCharsPointer(&vVerifiedRoute), tEndIndex + 1, pError))
					{vIsNoError = false;}

				if(vIsNoError && !crx_c_string_appendChars(&vEntityName, 
						crx_c_string_getCharsPointer(&vVerifiedRoute) + tEndIndex + 1, 
						crx_c_string_getSize(&vVerifiedRoute) - tEndIndex - 
						(vIsADirectory ? 2 : 1), pError))
					{vIsNoError = false;}
			}
			else
			{
				vIsNoError = crx_c_string_appendChars(&vEntityName, 
						crx_c_string_getCharsPointer(&vVerifiedRoute), 
						crx_c_string_getSize(&vVerifiedRoute) - (vIsADirectory ? 1 : 0), pError);
			}
		}
